package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatPrintTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testPrintWithValidAppendable() throws IOException {
        Appendable appendable = mock(Appendable.class);
        CSVPrinter printer = csvFormat.print(appendable);
        assertNotNull(printer);
        assertSame(appendable, printer.getOut());
    }

    @Test
    void testPrintWithAppendableThrowsIOException() throws IOException {
        Appendable appendable = mock(Appendable.class);
        doThrow(new IOException("append failed")).when(appendable).append(any(CharSequence.class));
        CSVPrinter printer = csvFormat.print(appendable);
        assertNotNull(printer);

        // To trigger IOException, call a method that writes to the Appendable
        IOException thrown = assertThrows(IOException.class, () -> {
            printer.print("test");
        });
        assertEquals("append failed", thrown.getMessage());
    }
}
